#include <stdlib.h>
#include <stdbool.h>

bool isSorted(int arr[], int n) {
	for (int i = 0; i < n - 1; i++) {
		if (arr[i] > arr[i + 1]) return false;
	}
	return true;
}

void bogosort(int arr[], int n) {
	while (!isSorted(arr, n)) {
		for (int i = 0; i < n; i++) {
			int j = rand() % n;
			int temp = arr[i];
			arr[i] = arr[j];
			arr[j] = temp;
		}
	}
}
